// Normalize incoming data from either source
let raw = $input.first().json;
if (raw.entry) raw = raw.entry[0].changes[0].value; // Facebook format
if (raw.rss) raw = raw.rss.channel.item; // RSS format

const listing = {
  title: raw.title || raw.name || '',
  description: raw.description || raw.content || raw.message || '',
  url: raw.link || raw.url || raw.permalink || '',
  price: raw.price || raw.amount || ''
};
return [listing];

// Check database for duplicate listing
const sqlite3 = require('sqlite3').verbose();
const path = '/home/ubuntu/smallsizedpuppy/data/listings.db';
const db = new sqlite3.Database(path);
const url = $input.first().json.url;
const isDuplicate = await new Promise((resolve) => {
  db.get('SELECT id FROM seen_listings WHERE url = ?', [url], (err, row) => {
    if (err || row) resolve(true);
    else {
      db.run('INSERT INTO seen_listings (url, title) VALUES (?, ?)', [url, $input.first().json.title]);
      resolve(false);
    }
    db.close();
  });
});
return [{ ...$input.first().json, isDuplicate }];

