// Extract URL from approval command
const content = $input.first().json.message.content;
const match = content.match(/!approve\s+(\S+)/);
const url = match ? match[1] : null;
if (!url) throw new Error('No URL in approval command');
// Fetch full listing from database or pass through
return [{ url, ...$input.first().json }];

// Route reply to correct Discord thread
const reply = $input.first().json;
// In production: lookup thread_id from database using reply's original listing URL
// For now, assume thread_id passed in webhook
const threadId = reply.thread_id;
const content = `**Seller replied:**\n${reply.body}`;
return [{ threadId, content }];

// Parse !schedule command from Discord
const cmd = $input.first().json.message.content;
const match = cmd.match(/!schedule\s+(.+?)\s+(.+)/);
const dateTime = match ? match[1] : 'unknown';
const contactInfo = match ? match[2] : 'unknown';
const alert = `📢 **GET YO DAMN FREE SMALL LITTLE DOG**\nFrom: ${$input.first().json.seller_name || 'seller'}\nMeet scheduled for: ${dateTime}\nContact info: ${contactInfo}\n\nText Evan: 4243353756`;
// Send SMS via email-to-SMS gateway
const smsEmail = `4243353756@mms.att.net`; // Adjust carrier as needed
return [{ alert, smsEmail, contactInfo, dateTime }];
